--
-- Name: fn_citas_validardoctor(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fn_citas_validardoctor() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF EXISTS (
        SELECT 1 FROM Personal p
        WHERE p.PersonalID = NEW.DoctorID
        AND p.TipoPersonal <> 'Doctor'
    ) THEN
        RAISE EXCEPTION 'Solo doctores pueden recibir citas';
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_citas_validardoctor() OWNER TO postgres;

--
-- Name: fn_detventa_descontarinventario(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fn_detventa_descontarinventario() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF EXISTS (
        SELECT 1
        FROM InventarioMedicinas inv
        WHERE inv.InventarioID = NEW.InventarioID
        AND inv.CantidadDisponible < NEW.Cantidad
    ) THEN
        RAISE EXCEPTION 'Stock insuficiente';
    END IF;

    UPDATE InventarioMedicinas
    SET CantidadDisponible = CantidadDisponible - NEW.Cantidad
    WHERE InventarioID = NEW.InventarioID;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_detventa_descontarinventario() OWNER TO postgres;

--
-- Name: fn_detventa_validarreceta(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fn_detventa_validarreceta() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF EXISTS (
        SELECT 1
        FROM Medicinas m
        JOIN VentasMedicina v ON NEW.VentaID = v.VentaID
        WHERE m.MedicinaID = NEW.MedicinaID
        AND m.RequiereReceta = TRUE
        AND v.RecetaID IS NULL
    ) THEN
        RAISE EXCEPTION 'Esta medicina requiere receta';
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_detventa_validarreceta() OWNER TO postgres;

--
-- Name: fn_ingresos_validaraforo(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fn_ingresos_validaraforo() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_ocupados    INT;
    v_maximo      INT;
    v_nombre_area VARCHAR(100);
BEGIN
    -- Contar camas ocupadas actualmente en el área
    SELECT COUNT(*)
    INTO v_ocupados
    FROM ingresoshospitalarios
    WHERE areaid = NEW.areaid
      AND estado = 'En Curso';

    -- Obtener aforo máximo del área
    SELECT aforoMaximo, nombre
    INTO v_maximo, v_nombre_area
    FROM areashospital
    WHERE areaid = NEW.areaid;

    IF v_ocupados >= v_maximo THEN
        RAISE EXCEPTION
            'Aforo maximo alcanzado en el area "%". Ocupados: % / %',
            v_nombre_area, v_ocupados, v_maximo;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_ingresos_validaraforo() OWNER TO postgres;

