--
-- Name: vista_para_knn; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vista_para_knn AS
 SELECT p.pacienteid,
    round((EXTRACT(year FROM age((p.fechanacimiento)::timestamp with time zone)) / 100.0), 4) AS edad_normalizada,
        CASE
            WHEN (lower((p.genero)::text) = ANY (ARRAY['male'::text, 'm'::text, 'masculino'::text])) THEN 1
            ELSE 0
        END AS genero_binario,
        CASE ts.propensiondpresion
            WHEN 'Hipertension'::text THEN 1
            WHEN 'Hipotension'::text THEN '-1'::integer
            ELSE 0
        END AS factor_presion,
    COALESCE(round((max(c.precio) / 2000000.0), 6), (0)::numeric) AS costo_normalizado,
        CASE
            WHEN ((ts.grupo)::text = 'A+'::text) THEN 1
            ELSE 0
        END AS tipo_ap,
        CASE
            WHEN ((ts.grupo)::text = 'A-'::text) THEN 1
            ELSE 0
        END AS tipo_an,
        CASE
            WHEN ((ts.grupo)::text = 'B+'::text) THEN 1
            ELSE 0
        END AS tipo_bp,
        CASE
            WHEN ((ts.grupo)::text = 'B-'::text) THEN 1
            ELSE 0
        END AS tipo_bn,
        CASE
            WHEN ((ts.grupo)::text = 'AB+'::text) THEN 1
            ELSE 0
        END AS tipo_abp,
        CASE
            WHEN ((ts.grupo)::text = 'AB-'::text) THEN 1
            ELSE 0
        END AS tipo_abn,
        CASE
            WHEN ((ts.grupo)::text = 'O+'::text) THEN 1
            ELSE 0
        END AS tipo_op,
        CASE
            WHEN ((ts.grupo)::text = 'O-'::text) THEN 1
            ELSE 0
        END AS tipo_on
   FROM (((public.pacientes p
     LEFT JOIN public.tiposanguineos ts ON ((p.tiposanguineoid = ts.tiposanguineoid)))
     LEFT JOIN public.citas ci ON ((ci.pacienteid = p.pacienteid)))
     LEFT JOIN public.consultas c ON ((c.citaid = ci.citaid)))
  GROUP BY p.pacienteid, p.fechanacimiento, p.genero, ts.propensiondpresion, ts.grupo;


ALTER VIEW public.vista_para_knn OWNER TO postgres;

